const express = require('express');
const app = express();

app.set('view engine', 'ejs');
app.use(express.static('public'));

// Mock Database (Step 5 & 8 in your plan)
const products = [
    { id: 1, name: 'iPhone 15 Pro', price: 999, category: 'Mobile', desc: 'Titanium build' },
    { id: 2, name: 'MacBook Air M3', price: 1299, category: 'Computers', desc: 'Powerful & Thin' },
    { id: 3, name: 'Sony WH-1000XM5', price: 349, category: 'Accessories', desc: 'Best noise canceling' }
];

// Routes
app.get('/', (req, res) => {
    res.render('index', { products: products });
});

app.get('/product/:id', (req, res) => {
    const product = products.find(p => p.id == req.params.id);
    res.render('details', { product: product });
});

app.listen(3000, () => console.log('ElectroShop running on http://localhost:3000'));